//   자동 조명등
const int WLED = 9;        // 백색 LED → 9번 핀 (PWM)
const int LIGHT = 0;       // 조도 센서 → A0 핀
const int MIN_LIGHT = 200; // 최소 조도 값
const int MAX_LIGHT = 900; // 최대 조도 값
int val = 0;

void setup() {
     pinMode(WLED, OUTPUT);
}

void loop() {
     val = analogRead(LIGHT);                      // 조도 읽기 (0~1023)
     val = map(val, MIN_LIGHT, MAX_LIGHT, 255, 0); // 역방향 매핑!
     val = constrain(val, 0, 255);                 // PWM 범위 제한
     analogWrite(WLED, val);                       // LED 밝기 출력
}
